24	
25	    // Title
26	    expect(
27	      screen.getByText('Enroll ACM managed application')
28	    ).toBeInTheDocument();
29	    // Close button
30	    expect(screen.getByRole('button', { name: /Close/i })).toBeInTheDocument();
31	    // Body
32	    expect(
33	      screen.getByText(
34	        'Follow the below steps to enroll your managed applications to disaster recovery:'
35	      )
36	    ).toBeInTheDocument();
37	    // Footer
38	    expect(
39	      screen.getByText('Continue to Applications page')
40	    ).toBeInTheDocument();
41	  });
42	
43	  it('Modal buttons working as expected', async () => {
44	    const user = userEvent.setup();
45	    render(<ManagedApplicationsModal isOpen={true} closeModal={closeModal} />);
46	
47	    await user.click(screen.getByText('Continue to Applications page'));
48	    expect(closeModal).toHaveBeenCalledTimes(1);
49	    expect(navigate).toHaveBeenCalledTimes(1);
50	  });
51	});

